const email = $('Gmail Trigger').first().json;
const allLabels = $('Get All Labels').all().map(item => item.json);

// Build available labels info
const availableLabels = ['Work', 'Newsletters', 'Social Media', 'Finance', 'Personal', 'To Review'];

return [{
  json: {
    messageId: email.id,
    from: email.from || 'Unknown',
    subject: email.subject || 'No subject',
    snippet: (email.snippet || '').substring(0, 500),
    allLabels: allLabels,
    prompt: `Categorize this email into ONE of these categories: Work, Newsletters, Social Media, Finance, Personal, To Review.

Email details:
- From: ${email.from || 'Unknown'}
- Subject: ${email.subject || 'No subject'}
- Preview: ${(email.snippet || '').substring(0, 300)}

Category definitions:
- Work: Professional emails, work tools (Slack, GitHub, Jira, Zoom, etc.), colleagues, business
- Newsletters: Subscriptions, digests, marketing emails, promotional content with unsubscribe links
- Social Media: Facebook, Twitter/X, LinkedIn, Instagram, YouTube, Discord, WhatsApp notifications
- Finance: Banks, payments, invoices, receipts, subscriptions, PayPal, Stripe, financial services
- Personal: Emails from friends, family, personal contacts (usually from gmail.com, outlook.com, etc.)
- To Review: Cannot determine category or doesn't fit others

Respond with ONLY the category name, nothing else. Example: "Work" or "Newsletters"`
  }
}];

const prepData = $('Prepare AI Prompt').first().json;
const aiResponse = $('AI Categorize').first().json;
const allLabels = prepData.allLabels;

// Extract category from AI response
let category = (aiResponse.content || aiResponse.message?.content || 'To Review').trim();

// Normalize the category name
const validCategories = ['Work', 'Newsletters', 'Social Media', 'Finance', 'Personal', 'To Review'];
const normalizedCategory = validCategories.find(c => 
  c.toLowerCase() === category.toLowerCase() ||
  category.toLowerCase().includes(c.toLowerCase())
) || 'To Review';

// Find label ID
const label = allLabels.find(l => l.name === normalizedCategory);

if (!label) {
  throw new Error(`Label "${normalizedCategory}" not found. Please run the Gmail Labels Setup workflow first.`);
}

return [{
  json: {
    messageId: prepData.messageId,
    from: prepData.from,
    subject: prepData.subject,
    aiCategory: category,
    labelName: normalizedCategory,
    labelId: label.id
  }
}];
